head.script:
requestAnimationFrame(() => {
  globalThis.__VERCEL_NAVIGATION_METRICS_RECORDED_MEASURES = globalThis.__VERCEL_NAVIGATION_METRICS_RECORDED_MEASURES || new Map();
  if (globalThis.__VERCEL_NAVIGATION_METRICS_RECORDED_MEASURES.has("content visible")) {

    return;
  }
  globalThis.__VERCEL_NAVIGATION_METRICS_RECORDED_MEASURES.set("content visible", "MarketingPageWrapper");

  try {
    performance.measure("content visible", {
      end: performance.now(),
      detail: {
        vercelNavigation: {
          isHardNavigation: true,
          attrs: JSON.parse("{\"phase\":\"content\",\"label\":\"MarketingPageWrapper\",\"route\":\"/precomputed/[experimentCode]/home/[homeFlagsCode]/redesign-2026\",\"target_env\":\"production\",\"state\":\"visible\"}"),
        },
        devtools: JSON.parse("{\"track\":\"Navigation Phases ▲\",\"color\":\"primary-dark\",\"properties\":[[\"Navigation Type\",\"hard\"],[\"Phase\",\"content\"],[\"Label\",\"MarketingPageWrapper\"],[\"Route\",\"/precomputed/[experimentCode]/home/[homeFlagsCode]/redesign-2026\"],[\"From Route\",\"undefined\"],[\"Target Env\",\"production\"],[\"State\",\"visible\"]]}")
      }
    });
  } catch {}
});

